// ---------------------------------------------------------------------------
// Design tokens
// ---------------------------------------------------------------------------
const COLORS = {
  bg: "#EEF1F6",
  panel: "#FFFFFF",
  ink: "#131A2B",
  inkSoft: "#5B6478",
  line: "#DDE3EE",
  navy: "#1B2A4A",
  amber: "#E3A008",
  teal: "#127475",
  coral: "#C4552E",
  positive: "#1E8F5F",
  neutral: "#8A93A6",
  negative: "#C4453E",
};
const PIE_COLORS = ["#1B2A4A", "#E3A008", "#127475", "#C4552E", "#7A6FF0", "#3D7A99", "#8A93A6", "#B0754A", "#4E9E5B", "#8E5572", "#3F6B4F", "#A85751", "#5B6478", "#2E5EAA", "#D9822B"];

function fmtNum(n) {
  if (n === null || n === undefined) return "—";
  if (Math.abs(n) >= 1000) return n.toLocaleString();
  return n.toString();
}
function fmtPct(n, digits = 1) {
  if (n === null || n === undefined) return "—";
  return `${n.toFixed(digits)}%`;
}

// ---------------------------------------------------------------------------
// Small building blocks
// ---------------------------------------------------------------------------
function KpiCard({ icon: Icon, label, value, sub, subTone }) {
  return (
    <div style={{
      background: COLORS.panel, borderRadius: 14, padding: "18px 20px",
      border: `1px solid ${COLORS.line}`, display: "flex", flexDirection: "column",
      gap: 10, minWidth: 0, position: "relative", overflow: "hidden",
    }}>
      <div style={{ position: "absolute", left: 0, top: 0, bottom: 0, width: 4, background: COLORS.amber }} />
      <div style={{ display: "flex", alignItems: "center", gap: 8, color: COLORS.inkSoft, paddingLeft: 6 }}>
        <Icon size={15} />
        <span style={{ fontSize: 12, fontWeight: 600, letterSpacing: 0.3, textTransform: "uppercase" }}>{label}</span>
      </div>
      <div style={{ fontSize: 26, fontWeight: 700, color: COLORS.navy, fontFamily: "'Space Grotesk', sans-serif", paddingLeft: 6 }}>
        {value}
      </div>
      {sub && (
        <div style={{ fontSize: 12, color: subTone || COLORS.inkSoft, paddingLeft: 6, display: "flex", alignItems: "center", gap: 4 }}>
          {sub}
        </div>
      )}
    </div>
  );
}

function Panel({ title, subtitle, children, right }) {
  return (
    <div style={{
      background: COLORS.panel, borderRadius: 14, border: `1px solid ${COLORS.line}`,
      padding: "20px 22px", display: "flex", flexDirection: "column", gap: 4,
    }}>
      <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", gap: 12, marginBottom: 8 }}>
        <div>
          <div style={{ fontSize: 15, fontWeight: 700, color: COLORS.navy, fontFamily: "'Space Grotesk', sans-serif" }}>{title}</div>
          {subtitle && <div style={{ fontSize: 12, color: COLORS.inkSoft, marginTop: 2 }}>{subtitle}</div>}
        </div>
        {right}
      </div>
      {children}
    </div>
  );
}

function TabButton({ active, onClick, children }) {
  return (
    <button
      onClick={onClick}
      style={{
        padding: "8px 16px", borderRadius: 999, border: `1px solid ${active ? COLORS.navy : COLORS.line}`,
        background: active ? COLORS.navy : "transparent", color: active ? "#fff" : COLORS.inkSoft,
        fontSize: 13, fontWeight: 600, cursor: "pointer", transition: "all 0.15s ease",
        fontFamily: "'IBM Plex Sans', sans-serif",
      }}
    >
      {children}
    </button>
  );
}

const CustomTooltip = ({ active, payload, label, formatter }) => {
  if (!active || !payload || !payload.length) return null;
  return (
    <div style={{
      background: COLORS.navy, color: "#fff", padding: "8px 12px", borderRadius: 8,
      fontSize: 12, fontFamily: "'IBM Plex Mono', monospace", boxShadow: "0 4px 14px rgba(0,0,0,0.2)",
    }}>
      <div style={{ opacity: 0.7, marginBottom: 4 }}>{label}</div>
      {payload.map((p, i) => (
        <div key={i} style={{ display: "flex", gap: 8, justifyContent: "space-between" }}>
          <span>{p.name}</span>
          <strong>{formatter ? formatter(p.value) : p.value}</strong>
        </div>
      ))}
    </div>
  );
};

